UPDATE items
SET name = #{name},
    description = #{description},
    image_url = #{imageUrl},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

UPDATE items
SET in_use_by_user_id = #{userId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler},
    in_use_at = #{inUseAt},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

UPDATE items
SET in_use_by_user_id = NULL,
    in_use_at = NULL,
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

UPDATE items
SET box_id = #{newBoxId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

